```bicep
// Minimal Bicep to ensure at least one Bastion Host exists in the subscription
param location string = resourceGroup().location

resource vnet 'Microsoft.Network/virtualNetworks@2022-07-01' = {
  name: '<example_resource_name>-vnet'
  location: location
  properties: {
    addressSpace: { addressPrefixes: ['10.0.0.0/24'] }
    subnets: [
      {
        name: 'AzureBastionSubnet'
        properties: { addressPrefix: '10.0.0.0/27' }
      }
    ]
  }
}

resource pip 'Microsoft.Network/publicIPAddresses@2022-07-01' = {
  name: '<example_resource_name>-pip'
  location: location
  sku: { name: 'Standard' }
  properties: { publicIPAllocationMethod: 'Static' }
}

resource bastion 'Microsoft.Network/bastionHosts@2024-10-01' = {
  name: '<example_resource_name>'
  location: location
  sku: { name: 'Basic' }
  properties: {
    ipConfigurations: [
      {
        name: 'IpConf'
        properties: {
          subnet: { id: resourceId('Microsoft.Network/virtualNetworks/subnets', vnet.name, 'AzureBastionSubnet') } // Critical: attaches Bastion to required AzureBastionSubnet so resource can be created
          publicIPAddress: { id: pip.id } // Critical: associates required Public IP with Bastion
        }
      }
    ]
  }
}
```

```bicep
// Enable NSG flow logs and send to Log Analytics
