  name: '<example_resource_name>/<example_resource_name>'
  location: '<REGION>'
  properties: {
    enabled: true // CRITICAL: turns on flow logs
    targetResourceId: '<example_resource_id>' // NSG resource ID
    storageId: '<example_resource_id>' // required for NSG flow logs
    flowAnalyticsConfiguration: {
      networkWatcherFlowAnalyticsConfiguration: {
        enabled: true // CRITICAL: sends flow logs to Log Analytics
        workspaceResourceId: '<example_resource_id>' // Log Analytics workspace resource ID
      }
    }
  }
}
