resource flowlog 'Microsoft.Network/networkWatchers/flowLogs@2023-09-01' = {
  name: '<example_resource_name>/<example_resource_name>'
  location: '<LOCATION>'
  properties: {
    targetResourceId: '<example_resource_id>'
    storageId: '<example_resource_id>'
    enabled: true           // critical: turns on flow logs
    retentionPolicy: {
      enabled: true         // critical: activates retention policy
      days: 90              // critical: 0 (unlimited) or >= 90 to pass
    }
  }
}
