// Configure a Storage Account to use Customer-Managed Keys (CMK)
resource sa 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: '<example_resource_name>'
  location: '<location>'
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
  identity: {
    type: 'SystemAssigned' // CRITICAL: required so the storage account can access the key vault
  }
  properties: {
    encryption: {
      keySource: 'Microsoft.Keyvault' // CRITICAL: switches encryption to CMK (Prowler checks for this)
      keyVaultProperties: {
        keyName: '<key_name>' // required key name
        keyVaultUri: 'https://<example_resource_name>.vault.azure.net/' // required Key Vault URI
      }
    }
  }
}
```

REMEDIATION_CODE_TERRAFORM:
