```bicep
// Create a Private Endpoint for a Storage Account to add a private endpoint connection (PASS)
param storageAccountId string  // ID of Microsoft.Storage/storageAccounts
param subnetId string          // ID of the subnet to host the Private Endpoint

resource pe 'Microsoft.Network/privateEndpoints@2023-05-01' = {
  name: '<example_resource_name>'
  location: resourceGroup().location
  properties: {
    subnet: { id: subnetId }
    privateLinkServiceConnections: [
      {
        name: 'conn'
        properties: {
          privateLinkServiceId: storageAccountId  // Critical: links the Private Endpoint to the storage account
          groupIds: ['blob']                      // Critical: targets Blob subresource, creating the private endpoint connection
        }
      }
    ]
  }
}
```

REMEDIATION_CODE_TERRAFORM:
```hcl
# Create a Private Endpoint for a Storage Account to add a private endpoint connection (PASS)
variable "resource_group_name" { type = string }
variable "location" { type = string }
variable "subnet_id" { type = string }
variable "storage_account_id" { type = string }

resource "azurerm_private_endpoint" "<example_resource_name>" {
  name                = "<example_resource_name>"
  resource_group_name = var.resource_group_name
  location            = var.location
  subnet_id           = var.subnet_id

  private_service_connection {
    name                           = "conn"
    private_connection_resource_id = var.storage_account_id  # Critical: links to the storage account
    subresource_names              = ["blob"]                # Critical: targets Blob subresource to create the connection
  }
}
```

